r:         tokens = ' '.join(cmd_list).split()     return tokens[0] if tokens else ''  stats = {} for ts, cmd, workdir, source in records:     key = main_command(cmd)     entry = stats.setdefault(key, {         'count':0,         'first':None,         'last':None,         'workdirs':set(),         'sources':set(),         'examples':set()     })     entry['count'] += 1     dt = parse_ts(ts)     if dt is not None:         if entry['first'] is None or dt < entry['first']:             entry['first'] = dt         if entry['last'] is None or dt > entry['last']:             entry['last'] = dt     entry['workdirs'].add(workdir)     entry['sources'].add(source)     entry['examples'].add(' '.join(cmd))  rows = sorted(stats.items(), key=lambda kv: (-kv[1]['count'], kv[0])) with out.open('w') as f:     f.write('main_command	count	first_seen_utc	last_seen_utc	workdir_count	source_log_count	examples
